    def __init__(self):
        self.history = []

    def calculate(self, op: str, a: int, b: int):
        result = None
        if op == "add":
            result = add(a, b)
        elif op == "subtract":
            result = subtract(a, b)
        elif op == "multiply":
            result = multiply(a, b)
        elif op == "divide":
            result = divide(a, b)
        self.history.append((op, a, b, result))
        return result

    def get_history(self):
        return self.history

    def clear_history(self):
        self.history = []

